import{_ as e,o as p,c as a,j as r,a as t,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"宝可梦技能—飞行","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—飞行.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—飞行.md"}'),n={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—飞行.md"};function s(o,b,_,l,i,c){return p(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"宝可梦技能—飞行",tabindex:"-1"},[t("宝可梦技能—飞行 "),r("a",{class:"header-anchor",href:"#宝可梦技能—飞行","aria-label":'Permalink to "宝可梦技能—飞行"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"汹涌疾风021")])])],-1),d('<h1 id="宝可梦技能—飞行-1" tabindex="-1">宝可梦技能—飞行 <a class="header-anchor" href="#宝可梦技能—飞行-1" aria-label="Permalink to &quot;宝可梦技能—飞行&quot;">​</a></h1><p>宝可梦技能—飞行</p><p>特别说明：飞行系技能中物理系技能造成的伤害均为挥砍伤害。法伤技能造成的均为力场伤害。<br> 飞行系技能皆有【法破】特性，不再赘述。</p><p>【起风】D+500<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：飞行系法伤技能，该宝可梦进行一次施法攻击检定，射程15米。本次检定中附带3dp的飞行能量加值，以及2点来自于飞行能量的附加成功。<br> 差价升级：C+1000<br> 差价升级后仍可使用技艺的较低级别版本。<br> 则本技能的射程提升至45米，攻击附带飞行能量加值提升至9dp，来自技艺的附加成功提升至3。</p><p>【翅膀攻击】C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：飞行系物理技能，该宝可梦进行一次近战攻击检定，本次检定中附带9dp的飞行能量加值，以及3点来自于技艺的附加成功，使用【9加骰】。<br> 差价升级至B+2000<br> 差价升级后仍可使用技艺的较低级别版本。<br> 则本技能攻击附带的附加成功提升至7，获得【8加骰】与【湮灭】特性。</p><p>【飞翔】C+1000<br> 指挥动作：整轮动作+下一回合的标准动作<br> 宝可梦消耗动作：整轮动作+下一回合的标准动作<br> 效果：飞行系物理技能，该宝可梦需要先进行一次全速移动飞起至空中，这意味着宝可梦会获得机动性为普通的飞行能力并在飞行状态下额外获得等同于该宝可梦敏捷属性点的闪避防御，持续一场景。下一回合，该宝可梦进行一次近战攻击检定造成挥砍伤害，这次攻击额外具有5高速、5破甲、5破魔。</p><p>【啄钻】C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：飞行系物理技能，该宝可梦进行一次近战攻击检定造成穿刺伤害，这次攻击附带6dp技艺加值和1点来自于技艺的附加成功并具有【高速5】，这次攻击命中后会造成2点不可豁免的剧痛点数（创伤来源）。<br> 差价升级至B+2000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：攻击附带技艺加值提升至8dp，剧痛点数（创伤来源）提升至4，高速提升至10，并具有【接触攻击】特性。</p><p>【神鸟猛击】C+1000<br> 蓄力技<br> 指挥动作：整轮动作+下一轮的标准动作。<br> 宝可梦消耗动作：整轮动作+下一轮的标准动作<br> 效果：飞行系物理技能，该宝可梦需要先消耗一个整轮动作进行蓄力，蓄力后直到下一轮开始前被称为蓄力过程，蓄力过程中宝可梦与训练家视为进行了全防御，且该宝可梦的攻击主属性获得等同于该属性值一半的增强加值，持续一个场景（该提升效果仅能触发一次）。下一轮该宝可梦可进行一次近战攻击检定，造成挥砍伤害。这次攻击中附带等同于宝可梦力量属性点的技艺加值以及2点来自技艺的附加成功。<br> 差价升级：B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级：第一轮获得的攻击主属性点的增强加值提升至等于该属性点，附加成功提升至5点并获得【毁灭】特性。<br> A级：本攻击触及范围提升至该宝可梦的敏感范围，本次攻击造成的伤害值提升一半，附加成功提升至9点。</p><p>【空气之刃】C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：飞行系法伤技能，该宝可梦进行一次施法攻击检定，这次攻击检定+9dp的飞行能量加值，射程30米。这次攻击额外具有10高速和5破甲的特性。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：这次攻击射程提升至90米，获得【能量武器】【8加骰】【湮灭】特性。攻击命中后附带伤害值一半的恐惧点数（创伤来源），正常豁免。<br> A级效果：这次攻击攻击检定附带的飞行能量加值提升为该宝可梦的施法属性值，射程提升至敏感范围，攻击命中后附带的恐惧点数（创伤来源）提升为等同于伤害值，正常豁免。本次攻击忽略对手的基础、闪避防御，这是一个A级的时空来源效果。</p><p>【燕返】C+1000<br> 指挥动作：标准动作。<br> 宝可梦消耗动作：标准动作<br> 效果：飞行系物理技能，该宝可梦进行一次近战攻击检定造成挥砍伤害，本次攻击获得9dp技艺加值以及1点来自技艺的附加成功。本次攻击具有【9加骰】【毁灭】特性。<br> 差价升级至B+2000<br> 差价升级后仍可使用技艺的较低级别版本。<br> 则本技能攻击中附带的技艺附加成功提升至3点，【9加骰】提升至【8加骰】，【毁灭】提升至【湮灭】，并获得【接触攻击】特性。</p><p>【弹跳】C+1000<br> 指挥动作：整轮动作+下一回合的标准动作<br> 宝可梦消耗动作：整轮动作+下一回合的标准动作<br> 效果：飞行系物理技能，该宝可梦需要先进行一次全速移动跃起至空中，这意味着宝可梦会获得机动性为普通的飞行能力并在飞行状态下额外获得等同于该宝可梦敏捷属性点的闪避防御，持续一场景。下一回合，该宝可梦进行一次近战攻击检定造成挥砍伤害，这次攻击额外附带2点不可豁免的麻痹点数（创伤来源）。</p><p>【羽栖】B+2000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：飞行系变化技能，该宝可梦进行一次原地降落并短暂休憩，获得等同于该宝可梦耐力点数的快速医疗点数（医疗点240），该快速医疗点数仅在本轮生效。<br> 特殊说明：使用了羽栖技能的宝可梦会暂时失去飞行能力，直到下一回合行动开始。</p><p>【顺风】B+2000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：飞行系变化技能，该宝可梦进行一次对飞行能量的操控，使以该宝可梦为圆心，半径60米内的所有友方单位获得等同于该宝可梦施法主属性点的先攻加值，持续一个场景。该先攻加值从下回合开始生效，该效果无法叠加。</p><p>【勇鸟猛攻】C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：整轮动作<br> 效果：飞行系物理技能，该宝可梦以一个整轮动作进行一次冲锋攻击，造成挥砍伤害，本次检定中附带9dp的飞行能量加值，本次攻击获得【9加骰】【高速5】【破甲5】【威猛5】。本次攻击会对使用者造成4点不可吸收豁免的严重伤害。<br> 差价升级：B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级：本次攻击检定附带飞行能量加值提升至宝可梦力量属性点，【高速】【破甲】【威猛】提升至10，使用【8加骰】，对自身造成不可吸收豁免的严重伤害提升至8点。<br> A级：本次攻击检定附带的飞行能量加值提升至力量属性点，本次攻击检定造成伤害提升一倍，获得8加骰。冲锋额外获得360米移动速度并无视A级及以下的困难地形效果，【高速】【破甲】【威猛】提升至20点。忽略对手的偏斜防御，这是A级创伤来源的效果。<br> 对自身造成不可吸收豁免的严重伤害提升至12点。</p><p>【自由落体】B+2000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：整轮动作+下一轮的标准动作。<br> 描述：宝可梦会携带着目标向天空飞去（跃起），接着在空中环绕并携带目标以惊人的势能向地面俯冲，借助引力与速度给予对手重创。<br> 效果：飞行系物理技能，该宝可梦以近战攻击检定对触及范围内的一个目标进行一次擒抱。擒抱检定命中后，目标会立即进入B级创伤来源的定身状态。接着宝可梦会携带目标往天空进行一次移动。在下一轮宝可梦会带着目标俯冲而下，将目标重重的摔在地面上。目标需要进行两次强韧豁免。第一次强韧豁免DC为宝可梦近战攻击检定的成功数+4，失败则受到差值的力场伤害。第二次强韧豁免其从高空坠落所受到的坠落伤害，坠落高度为宝可梦这一轮与上一轮所处于相对地面的最高位置。这之后，目标受到的定身状态解除，并在一场景内飞行机动性下降二级（完美-良好-普通-笨拙），若下降至笨拙以下，则目标无法进行飞行，这是一个B级创伤来源的负面效果。<br> 特殊的，若目标没有进入定身状态，其在自己行动轮内可发起与宝可梦的擒抱对抗，若成功则可脱离自由落体效果影响，其所处的位置与脱离擒抱时宝可梦位置相同。</p><p>【杂技】C+1000<br> 指挥动作：标准动作。<br> 宝可梦消耗动作：标准动作<br> 效果：飞行系物理技能，该宝可梦进行一次近战攻击检定造成挥砍伤害，本次攻击获得等同于宝可梦力量属性点一半的技艺加值，以及2点来自于技艺的附加成功。<br> 若使用该技艺的宝可梦身上并没有携带宝可梦奇物（装备），则该技艺加值翻倍。<br> 差价升级至B+2000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：本技能攻击中附带的技艺附加成功提升至5点，并获得【高速11】【接触攻击】特性。</p><p>【暴风】A+4000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：飞行系法伤技能，该宝可梦进行一次施法攻击检定，这次攻击具有等同于该宝可梦施法属性的飞行能量加值，射程355米。这次攻击具有【8加骰】，【湮灭】特性，忽略对手的力场、闪避防御，这是一个A级的环境来源效果。</p><p>【双翼】B+2000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：整轮动作<br> 效果：飞行系物理技能，该宝可梦进行一次投掷攻击检定造成挥砍伤害，本次攻击检定获得6dp技艺加值和1点来自技艺的附加成功，本次攻击具有【连射】【毁灭】【高速5】【破魔5】【8加骰】【接触攻击】特性。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',20)])])}const A=e(n,[["render",s]]);export{h as __pageData,A as default};
